-- V8: Restore V6 ground truth for delisted symbols whose sector was clobbered by
-- IngestionService.fetchAndSaveSupplementaryData (overwrote V6's EDGAR-SIC-derived
-- sector with EODHD's raw response — most commonly 'Other' for ~595 symbols, plus
-- proper-case variants like 'Financials' / 'Healthcare' for ~700 more).
--
-- The new delisted-immutable rule (PR feature/sector-normalization) prevents any
-- future re-clobber, so V8 is the last chance to canonicalize these rows.
--
-- Strategy: re-INSERT V6's exact rows with ON CONFLICT DO UPDATE (instead of V6's
-- DO NOTHING). V6-survivors get rewritten with the same value (no-op); clobbered
-- rows get restored. Idempotent: re-running V8 yields identical results.
--
-- Schema check constraints at the end enforce I1 + I2 (sector + sector_symbol must
-- be in the canonical 11) at the DB layer, so a future code regression cannot
-- reintroduce non-canonical values.


-- Cleanup: 3 active rows where the upstream provider returned 'NONE' instead of a
-- real sector. The new SectorNormalizer treats 'NONE' as null, but the gate skips
-- the update so these rows would otherwise stay stuck. Force them to NULL here.
UPDATE symbols SET sector = NULL, sector_symbol = NULL WHERE sector = 'NONE';

-- Defensive sweep: catch any remaining non-canonical sector / sector_symbol values
-- not covered by the V6 INSERT block above (e.g. an active symbol with a
-- proper-case sector that the V6 snapshot doesn't include, or any value introduced
-- via Adminer / psql since V6 ran). Without this, the chk_sector_canonical CHECK
-- constraint below would reject the migration on PRD if such a row exists.
-- Setting them to NULL forces re-evaluation on the next ingest via SectorNormalizer.
UPDATE symbols SET sector = NULL, sector_symbol = NULL
WHERE sector IS NOT NULL AND sector NOT IN (
    'TECHNOLOGY', 'FINANCIAL SERVICES', 'HEALTHCARE', 'ENERGY', 'INDUSTRIALS',
    'CONSUMER CYCLICAL', 'CONSUMER DEFENSIVE', 'COMMUNICATION SERVICES',
    'BASIC MATERIALS', 'REAL ESTATE', 'UTILITIES'
);
UPDATE symbols SET sector_symbol = NULL
WHERE sector_symbol IS NOT NULL AND sector_symbol NOT IN (
    'XLK', 'XLF', 'XLV', 'XLE', 'XLI', 'XLY', 'XLP', 'XLC', 'XLB', 'XLRE', 'XLU'
);

-- Hard DB invariants for I1 (sector) and I2 (sector_symbol). Even if app code
-- regresses, bad inserts get rejected at the boundary. These are checked once;
-- they will succeed because the INSERT...UPDATE block above has restored every
-- delisted row to canonical values, and active rows go through SectorNormalizer.
ALTER TABLE symbols ADD CONSTRAINT chk_sector_canonical
    CHECK (sector IS NULL OR sector IN (
        'TECHNOLOGY', 'FINANCIAL SERVICES', 'HEALTHCARE', 'ENERGY', 'INDUSTRIALS',
        'CONSUMER CYCLICAL', 'CONSUMER DEFENSIVE', 'COMMUNICATION SERVICES',
        'BASIC MATERIALS', 'REAL ESTATE', 'UTILITIES'
    ));

ALTER TABLE symbols ADD CONSTRAINT chk_sector_symbol_canonical
    CHECK (sector_symbol IS NULL OR sector_symbol IN (
        'XLK', 'XLF', 'XLV', 'XLE', 'XLI', 'XLY', 'XLP', 'XLC', 'XLB', 'XLRE', 'XLU'
    ));
